// Parses the structured TrainingPeaks CoachMatch email body
const results = [];

// Fixes a confirmed UTF-8-read-as-Latin-1 encoding bug from the IMAP source
// (e.g. "JosuÃ©" -> "Josué"). Safe no-op on text that doesn't have the issue.
const fixEncoding = (str) => {
  try {
    return Buffer.from(str, 'latin1').toString('utf8');
  } catch (e) {
    return str;
  }
};

for (const item of $input.all()) {
  const body = fixEncoding(item.json.textPlain || '');

  // Captures multi-line wrapped values, stopping at the next blank line
  // (field boundary) or end of string -- not just the next line break.
  const extract = (label) => {
    const re = new RegExp(label + '\\s*:?\\s*([\\s\\S]+?)(?:\\r?\\n\\s*\\r?\\n|$)', 'i');
    const match = body.match(re);
    return match ? match[1].replace(/\r?\n/g, ' ').replace(/\s+/g, ' ').trim() : '';
  };

  const fullName = extract('Athlete Name');
  const nameParts = fullName.split(/\s+/);
  const lastname = nameParts.pop() || '';
  const firstname = nameParts.join(' ');

  const location = extract('Location');
  const [city, state, country] = location.split(',').map(s => (s || '').trim());

  results.push({
    json: {
      firstname,
      lastname,
      email: extract('Email'),
      phone_raw: extract('Phone'),
      city: city || '',
      state: state || '',
      country: country || '',
      sport_raw: extract('What are you training for\\?'),
      athlete_level_raw: extract('Ability Level'),
      lead_notes: extract('Please give us more details about what you are looking for in a coach:'),
      source_subject: item.json.subject,
      source_date: item.json.date,
    }
  });
}

return results;

// Maps raw parsed fields to Twenty-CRM-ready values

const countryCallingCodes = {
  'argentina': '54', 'bolivia': '591', 'brazil': '55', 'chile': '56',
  'colombia': '57', 'costa rica': '506', 'cuba': '53',
  'dominican republic': '1', 'ecuador': '593', 'el salvador': '503',
  'guatemala': '502', 'honduras': '504', 'mexico': '52', 'nicaragua': '505',
  'panama': '507', 'paraguay': '595', 'peru': '51', 'puerto rico': '1',
  'spain': '34', 'united states': '1', 'usa': '1', 'uruguay': '598',
  'venezuela': '58', 'canada': '1'
};

const countryIso = {
  'argentina': 'AR', 'bolivia': 'BO', 'brazil': 'BR', 'chile': 'CL',
  'colombia': 'CO', 'costa rica': 'CR', 'cuba': 'CU',
  'dominican republic': 'DO', 'ecuador': 'EC', 'el salvador': 'SV',
  'guatemala': 'GT', 'honduras': 'HN', 'mexico': 'MX', 'nicaragua': 'NI',
  'panama': 'PA', 'paraguay': 'PY', 'peru': 'PE', 'puerto rico': 'PR',
  'spain': 'ES', 'united states': 'US', 'usa': 'US', 'uruguay': 'UY',
  'venezuela': 'VE', 'canada': 'CA'
};

const sportKeywords = {
  'running': ['run'],
  'cycling': ['cycl', 'bike', 'biking'],
  'swimming': ['swim'],
  'triathlon': ['triathlon', 'tri '],
  'duathlon': ['duathlon']
};

const levelOptions = ['No experience', 'Beginner', 'Intermediate', 'Advanced', 'Elite'];

// Twenty stores select/enum values as UPPER_SNAKE_CASE, not the label text
const toEnum = (str) => (str || '').toUpperCase().trim().replace(/[^A-Z0-9]+/g, '_').replace(/^_+|_+$/g, '');

const results = [];

for (const item of $input.all()) {
  const d = item.json;
  const countryKey = (d.country || '').toLowerCase().trim();
  const digitsOnly = (d.phone_raw || '').replace(/\D/g, '');
  const callingCode = countryCallingCodes[countryKey];
  const iso = countryIso[countryKey];

  let phone_local = null, phone_country_iso = null, phone_wa = null, no_phone = false;
  if (callingCode && iso && digitsOnly.length >= 7) {
    // Twenty wants the local number without the calling code
    phone_local = digitsOnly.startsWith(callingCode) ? digitsOnly.slice(callingCode.length) : digitsOnly;
    phone_country_iso = iso;
    // WhatsApp links need the full number WITH calling code, no +
    phone_wa = digitsOnly.startsWith(callingCode) ? digitsOnly : callingCode + digitsOnly;
  } else {
    no_phone = true;
  }

  const sportText = (d.sport_raw || '').toLowerCase();
  let sport = '';
  for (const [option, keywords] of Object.entries(sportKeywords)) {
    if (keywords.some(k => sportText.includes(k))) {
      sport = option;
      break;
    }
  }

  const levelText = (d.athlete_level_raw || '').toLowerCase().trim();
  const athlete_level = levelOptions.find(opt => opt.toLowerCase() === levelText) || '';

  const preferred_language = countryKey === 'brazil' ? 'Portuguese' : 'Spanish';

  results.push({
    json: {
      firstname: d.firstname,
      lastname: d.lastname,
      email: d.email,
      phone_local,
      phone_country_iso,
      phone_wa,
      no_phone,
      city: d.city,
      state: d.state,
      country: d.country,
      sport_enum: toEnum(sport),
      athlete_level_enum: toEnum(athlete_level),
      lead_notes: d.lead_notes,
      preferred_language_enum: toEnum(preferred_language),
      lead_source_enum: toEnum('TrainingPeaks CoachMatch'),
      lead_status_enum: toEnum('New'),
    }
  });
}

return results;

// Builds the create-person request. Query and variables are kept separate
// so quotes/apostrophes in free text (like lead notes) can't break anything.

const results = [];

for (const item of $input.all()) {
  const d = item.json;

  // City/country fallback: prefer city, fall back to state/region if city is blank
  const addressCity = d.city || d.state || '';
  const addressCountry = d.country || '';

  const data = {
    name: { firstName: d.firstname, lastName: d.lastname },
    emails: { primaryEmail: d.email },
    leadSource: 'COACHMATCH',
    leadStatus: 'NEW',
    leadNotes: d.lead_notes,
    addressCity,
    addressCountry,
    preferredLanguage: d.preferred_language_enum,
  };

  if (!d.no_phone) {
    data.phones = {
      primaryPhoneNumber: d.phone_local,
      primaryPhoneCountryCode: d.phone_country_iso,
    };
  }

  if (d.sport_enum) data.sport = d.sport_enum;
  if (d.athlete_level_enum) data.athleteLevel = d.athlete_level_enum;

  results.push({
    json: {
      query: 'mutation CreatePerson($data: PersonCreateInput!) { createPerson(data: $data) { id } }',
      variables: { data },
    },
  });
}

return results;

const lead = $('Code in JavaScript1').item.json;
const conflictId = ($json.errors && $json.errors[0] && $json.errors[0].extensions && $json.errors[0].extensions.conflictingRecordId) || '';
const waLink = lead.phone_wa ? `https://wa.me/${lead.phone_wa}` : null;

const lines = [
  `🔁 Lead repetido: ${lead.firstname} ${lead.lastname}`,
  `📧 ${lead.email}`,
  waLink ? `📱 ${waLink}` : `📱 Sin telefono valido`,
  `🪪 ID en Twenty: ${conflictId}`,
];

return [{ json: { telegram_message: lines.join('\n') } }];

const lead = $('Code in JavaScript1').item.json;

const message = `Hola ${lead.firstname}\n\nMi nombre es Iván, de Triaperformance, soy coach certificado y partner de Training Peaks. Te contacto ya que solicitaste información en Training Peaks sobre coaching personalizado.\n\nCuentame, con qué objetivo y cómo estás entrenando hoy en día?`;

const waLink = lead.phone_wa
  ? `https://wa.me/${lead.phone_wa}?text=${encodeURIComponent(message)}`
  : null;

const summaryLines = [
  `✅ ${lead.firstname} ${lead.lastname} · ${lead.country} · ${lead.sport_enum || 'sin deporte'} · ${lead.athlete_level_enum || 'sin nivel'}`,
  waLink ? `📱 ${waLink}` : `⚠️ Sin telefono, contactar por email: ${lead.email}`,
];

return [{ json: { telegram_message: summaryLines.join('\n') } }];

